1	//! Prompt injection detector.
2	//!
3	//! Scans page content for instruction-override attacks. Pipeline:
4	//! 1. Zero-width character scan
5	//! 2. Homoglyph detection
6	//! 3. Hidden content detection (display:none, visibility:hidden, aria-label traps)
7	//! 4. Instruction-override pattern matching
8	//!
9	//! Produces a score 0.0 (safe) to 1.0 (definite injection).
10	//! Target: <5ms scan time for typical pages.
11	
12	use ans_core::immune::{InjectionAction, InjectionFlag, InjectionLocation, InjectionScanResult};
13	
14	use crate::rules::{self};
15	
16	/// The prompt injection detector.
17	pub struct InjectionDetector;
18	
19	impl InjectionDetector {
20	    /// Scan page content for injection attempts.
21	    ///
22	    /// `url` provides context (some attacks are URL-specific).
23	    /// `raw_content` is the full page text: visible text + attributes + hidden content.
24	    #[must_use] 
25	    pub fn scan(&self, url: &str, raw_content: &str) -> InjectionScanResult {
26	        let start = std::time::Instant::now();
27	        let mut flagged: Vec<InjectionFlag> = Vec::new();
28	        let mut max_score: f32 = 0.0;
29	
30	        // ── Stage 1: Zero-width characters ──────────────────────
31	        let zw_chars = rules::contains_zero_width_chars(raw_content);
32	        if !zw_chars.is_empty() {
33	            let snippet: String = zw_chars.iter().take(10).map(|(c, _)| *c).collect();
34	            max_score = max_score.max(0.7);
35	            flagged.push(InjectionFlag {
36	                content_snippet: snippet,
37	                pattern_matched: format!("{} zero-width characters detected", zw_chars.len()),
38	                location: InjectionLocation::ZeroWidthChars,
39	                confidence: 0.8,
40	            });
41	        }
42	
43	        // ── Stage 2: Homoglyph detection ────────────────────────
44	        let h_score = rules::homoglyph_score(raw_content);
45	        if h_score > 0.2 {
46	            let snippets = rules::find_homoglyphs(raw_content);
47	            if !snippets.is_empty() {
48	                max_score = max_score.max(h_score);
49	                flagged.push(InjectionFlag {
50	                    content_snippet: snippets.join(", "),
51	                    pattern_matched: format!("homoglyph ratio {:.0}%", h_score * 100.0),
52	                    location: InjectionLocation::Homoglyph,
53	                    confidence: h_score,
54	                });
55	            }
56	        }
57	
58	        // ── Stage 3: Hidden content detection ───────────────────
59	        let hidden = detect_hidden_content(raw_content);
60	        for h in hidden {
61	            max_score = max_score.max(h.confidence);
62	            flagged.push(h);
63	        }
64	
65	        // ── Stage 4: Instruction-override rules ─────────────────
66	        for rule in &rules::injection_rules() {
67	            if let Some(m) = rule.pattern.find(raw_content) {
68	                max_score = max_score.max(rule.confidence);
69	                let snippet = raw_content[m.start()..]
70	                    .chars()
71	                    .take(80)
72	                    .collect::<String>();
73	                flagged.push(InjectionFlag {
74	                    content_snippet: snippet,
75	                    pattern_matched: rule.name.clone(),
76	                    location: classify_injection_location(&rule.name),
77	                    confidence: rule.confidence,
78	                });
79	            }
80	        }
81	
82	        // ── URL-based context boost ─────────────────────────────
83	        // Pages loaded from suspicious domains get a slight boost
84	        if is_suspicious_url(url) {
85	            max_score = (max_score + 0.15).min(1.0);
86	        }
87	
88	        let _scan_time_us = start.elapsed().as_micros() as i64;
89	
90	        InjectionScanResult {
91	            score: max_score,
92	            flagged_content: flagged,
93	            action: InjectionAction::from_score(max_score),
94	        }
95	    }
96	}
