98	// ── Hidden Content Detection ────────────────────────────────────────────
99	
100	fn detect_hidden_content(raw: &str) -> Vec<InjectionFlag> {
101	    let mut flags = Vec::new();
102	
103	    // display:none with substantial text content
104	    let display_none_re =
105	        regex::Regex::new(r#"(?is)style\s*=\s*"[^"]*display\s*:\s*none[^"]*"[^>]*>([^<]{20,})"#)
106	            .expect("invalid display:none regex");
107	    for cap in display_none_re.captures_iter(raw) {
108	        let text = cap
109	            .get(1)
110	            .map(|m| m.as_str().trim().to_string())
111	            .unwrap_or_default();
112	        if contains_instruction_pattern(&text) {
113	            flags.push(InjectionFlag {
114	                content_snippet: text.chars().take(100).collect(),
115	                pattern_matched: "display:none with instruction content".into(),
116	                location: InjectionLocation::DisplayNone,
117	                confidence: 0.85,
118	            });
119	        }
120	    }
121	
122	    // visibility:hidden / opacity:0 with text
123	    let hidden_re = regex::Regex::new(
124	        r#"(?is)style\s*=\s*"[^"]*(?:visibility\s*:\s*hidden|opacity\s*:\s*0)[^"]*"[^>]*>([^<]{20,})"#,
125	    )
126	    .expect("invalid hidden element regex");
127	    for cap in hidden_re.captures_iter(raw) {
128	        let text = cap
129	            .get(1)
130	            .map(|m| m.as_str().trim().to_string())
131	            .unwrap_or_default();
132	        if contains_instruction_pattern(&text) {
133	            flags.push(InjectionFlag {
134	                content_snippet: text.chars().take(100).collect(),
135	                pattern_matched: "hidden element with instruction content".into(),
136	                location: InjectionLocation::HiddenDiv,
137	                confidence: 0.8,
138	            });
139	        }
140	    }
141	
142	    // aria-label with instruction-like content
143	    let aria_re = regex::Regex::new(r#"(?is)aria-label\s*=\s*"([^"]{30,})""#).expect("invalid aria-label regex");
144	    for cap in aria_re.captures_iter(raw) {
145	        let text = cap
146	            .get(1)
147	            .map(|m| m.as_str().to_string())
148	            .unwrap_or_default();
149	        if contains_instruction_pattern(&text) {
150	            flags.push(InjectionFlag {
151	                content_snippet: text.chars().take(100).collect(),
152	                pattern_matched: "aria-label with instruction content".into(),
153	                location: InjectionLocation::AriaLabel,
154	                confidence: 0.75,
155	            });
156	        }
157	    }
158	
159	    flags
160	}
