162	/// Check whether text contains instruction-override patterns.
163	///
164	/// Covers common prompt injection vectors: instruction overrides, role-playing
165	/// attacks, persona-switching, and obfuscated payloads. Uses both substring
166	/// matching for speed and regex for compound patterns.
167	fn contains_instruction_pattern(text: &str) -> bool {
168	    let lower = text.to_lowercase();
169	
170	    // Fast substring checks for common injection keywords
171	    let quick_hit = lower.contains("ignore")
172	        || lower.contains("instruction")
173	        || lower.contains("you are")
174	        || lower.contains("system prompt")
175	        || lower.contains("do not")
176	        || lower.contains("override")
177	        || lower.contains("bypass")
178	        || lower.contains("forget")
179	        || lower.contains("stop everything")
180	        || lower.contains("new prompt")
181	        || lower.contains("the above")
182	        || lower.contains("the previous")
183	        || lower.contains("do anything now")
184	        || lower.contains("developer mode")
185	        || lower.contains("god mode")
186	        || lower.contains("jailbreak");
187	    if quick_hit {
188	        return true;
189	    }
190	
191	    // Regex-based compound pattern checks (compiled once via std::sync::LazyLock)
192	    use std::sync::LazyLock;
193	    static INSTRUCTION_REGEX: LazyLock<regex::Regex> = LazyLock::new(|| {
194	        regex::Regex::new(
195	            r"(?is)(?:forget\s+(?:all\s+)?(?:your\s+)?(?:previous\s+)?instructions?|you\s+are\s+(?:now|no\s+longer|a\s+different)|(?:new|updated|replacement)\s+system\s+prompt|do\s+not\s+follow|the\s+(?:above|previous|preceding)\s+(?:text|message|content)|ignore\s+(?:all\s+)?prior|stop\s+responding|your\s+(?:new|real)\s+(?:role|purpose|goal)\s+is)",
196	        )
197	        .expect("invalid instruction-override regex")
198	    });
199	
200	    INSTRUCTION_REGEX.is_match(&lower)
201	}
