203	/// Classify which injection location a rule targets.
204	fn classify_injection_location(rule_name: &str) -> InjectionLocation {
205	    match rule_name {
206	        "ignore_previous_instructions" | "new_instructions_colon" | "do_not_follow" => {
207	            InjectionLocation::HiddenDiv
208	        }
209	        "system_prompt_override" => InjectionLocation::MetaTag,
210	        "base64_injection" => InjectionLocation::InlineScript,
211	        _ => InjectionLocation::Unknown,
212	    }
213	}
