216	fn is_suspicious_url(url: &str) -> bool {
217	    let lower = url.to_lowercase();
218	    lower.contains("pastebin.com")
219	        || lower.contains("raw.githubusercontent")
220	        || lower.contains("gist.github")
221	        || lower.contains("data:text/html")
222	        || lower.contains("javascript:")
223	}
